@@ -5675,16 +5676,24 @@ void VPlanTransforms::optimizeFindIVReductions(VPlan &Plan,
                      PhiR->getRecurrenceKind()))
       continue;

-    // Get the IV and condition from the backedge value of the reduction phi.
